// Split aggregated binaries into one item per image.
// Each item carries the binary so subsequent HTTP Request nodes can upload it.
const aggregated = $('Aggregate Files').first();
const pageId = $('Add Page to Notion').first().json.id;
const binaries = aggregated.binary || {};

const keys = Object.keys(binaries);
if (keys.length === 0) {
  throw new Error('No binary images found in Aggregate output');
}

return keys.map(key => ({
  json: {
    binaryKey: key,
    pageId,
    mimeType: binaries[key].mimeType || 'image/jpeg',
    fileName: binaries[key].fileName || `photo-${key}.jpg`,
  },
  binary: {
    currentFile: binaries[key]
  }
}));

// HTTP Request (Create Upload Session) replaces the item json with the API response,
// clearing any binary data from the input. Re-attach the binary here by pairing
// each session item with its corresponding item from Get Binary Keys (by index).
const sessionItems = $('Initiate Notion Upload Session').all();
const binaryItems = $('Extract Image Keys').all();

return sessionItems.map((sessionItem, i) => ({
  json: {
    upload_id: sessionItem.json.id,
    upload_url: sessionItem.json.upload_url,
    pageId: binaryItems[i].json.pageId,
    mimeType: binaryItems[i].json.mimeType,
    fileName: binaryItems[i].json.fileName,
  },
  binary: {
    currentFile: binaryItems[i].binary.currentFile
  }
}));

// After all images have been uploaded, collect every upload_id from
// Attach Binary Context and build the Notion Files property payload.
const contextItems = $('Attach Upload Context').all();
const pageId = contextItems[0].json.pageId;

const files = contextItems.map(item => ({
  type: 'file_upload',
  file_upload: { id: item.json.upload_id }
}));

return [{ json: { pageId, files } }];
